using System;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.Extensions.Configuration;

namespace FunctionApp1
{
    public static class Function1
    {
        [FunctionName("Function1")]
        public static async Task<IActionResult> Run(
            [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequestData req,
            ILogger logger)
        {
            logger.LogInformation("C# HTTP trigger function processed a request.");

            var config = new ConfigurationBuilder()
                .AddAzureKeyVault(new AzureKeyVaultConfigurationOptions
                {
                    VaultName = Environment.GetEnvironmentVariable("KEY_VAULT_NAME"),
                    ClientId = Environment.GetEnvironmentVariable("CLIENT_ID")
                })
                .Build();

            string name = req.GetHeaderValue<string>("name");
            logger.LogInformation($"name: {name}");

            try
            {
                // Database query with parameters
                var databaseQuery = "SELECT * FROM customers WHERE country='USA'";

                using (var conn = new SqlConnection(config["ConnectionString"]))
                {
                    await conn.OpenAsync();

                    var cmd = new SqlCommand(databaseQuery, conn);
                    var result = await cmd.ExecuteReaderAsync();

                    while (await result.ReadAsync())
                    {
                        logger.LogInformation($"Customer {result[0]} from {result[1]}");
                    }
                }

                return new OkResult();
            }
            catch (Exception ex)
            {
                logger.LogError(ex, "An error occurred.");
                return new BadRequestObjectResult(new { message = "An error occurred." });
            }
        }
    }
